const items = $input.all();

function num(value, fallback = null) {
  if (value === undefined || value === null || value === '') return fallback;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function bool(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return ['true', '1', 'si', 'sí', 'yes'].includes(value.toLowerCase());
  return Boolean(value);
}

return items.map((item) => {
  const body = item.json.body ?? item.json;

  const pacienteId = body.paciente_id ?? body.pacienteId ?? body.patient_id ?? body.patientId ?? null;
  const dispositivoId = body.dispositivo_id ?? body.dispositivoId ?? body.device_id ?? body.deviceId ?? 'wearos-simulado';

  const heartRate = num(body.heart_rate ?? body.frecuencia_cardiaca ?? body.hr, 0);
  const spo2 = num(body.spo2 ?? body.oxigenacion, null);
  const systolicBp = num(body.systolic_bp ?? body.presion_sistolica ?? body.sbp, null);
  const diastolicBp = num(body.diastolic_bp ?? body.presion_diastolica ?? body.dbp, null);
  const cholesterol = num(body.cholesterol ?? body.colesterol, null);
  const glucose = num(body.glucose ?? body.glucosa, null);
  const age = num(body.age ?? body.edad, null);
  const smoker = bool(body.smoker ?? body.fumador ?? false);

  const flags = [];
  if (heartRate >= 130) flags.push('taquicardia >= 130 bpm');
  if (heartRate > 0 && heartRate <= 45) flags.push('bradicardia <= 45 bpm');
  if (spo2 !== null && spo2 <= 92) flags.push('SpO2 <= 92%');
  if (systolicBp !== null && systolicBp >= 160) flags.push('presion sistolica >= 160 mmHg');
  if (diastolicBp !== null && diastolicBp >= 100) flags.push('presion diastolica >= 100 mmHg');
  if (cholesterol !== null && cholesterol >= 240) flags.push('colesterol >= 240 mg/dL');
  if (glucose !== null && glucose >= 180) flags.push('glucosa >= 180 mg/dL');

  const requierePrediccion = flags.length > 0;

  return {
    json: {
      paciente_id: pacienteId,
      dispositivo_id: dispositivoId,
      timestamp: body.timestamp ?? new Date().toISOString(),
      heart_rate: heartRate,
      spo2,
      systolic_bp: systolicBp,
      diastolic_bp: diastolicBp,
      cholesterol,
      glucose,
      age,
      sex: body.sex ?? body.sexo ?? null,
      chest_pain_type: body.chest_pain_type ?? body.tipo_dolor_pecho ?? null,
      smoker,
      previous_condition: bool(body.previous_condition ?? body.antecedente_cardiaco ?? false),
      raw_payload: body,
      flags_umbral: flags,
      requiere_prediccion: requierePrediccion,
      severidad_reglas: flags.length >= 3 ? 'ALTA' : flags.length >= 1 ? 'MEDIA' : 'BAJA',
      config: {
        backend_base_url: 'http://host.docker.internal:8000',
        microservice_base_url: 'http://host.docker.internal:8010',
        backend_jwt: 'CAMBIAR_JWT_BACKEND',
        telegram_bot_token: 'CAMBIAR_TOKEN_TELEGRAM',
        telegram_chat_id: 'CAMBIAR_CHAT_ID'
      }
    }
  };
});

const original = $('Normalizar y evaluar umbrales').first().json;
const pred = $input.first().json ?? {};

const failed = pred.error !== undefined || pred.message?.includes?.('ECONNREFUSED');

let riesgo = pred.riesgo ?? pred.risk_level ?? pred.clase ?? null;
let score = pred.score ?? pred.probabilidad ?? pred.risk_score ?? null;
let fuente = pred.modelo ?? pred.model ?? 'microservice_metaheuristica';

if (failed || riesgo === null) {
  const n = original.flags_umbral.length;
  riesgo = n >= 3 ? 'ALTO' : n >= 1 ? 'MEDIO' : 'BAJO';
  score = n >= 3 ? 0.85 : n >= 1 ? 0.62 : 0.25;
  fuente = 'fallback_reglas_n8n_por_fallo_microservice';
}

const prioridad = riesgo === 'ALTO' || score >= 0.75 ? 'CRITICA' : riesgo === 'MEDIO' || score >= 0.50 ? 'ALTA' : 'MEDIA';

const resumen = `Paciente ${original.paciente_id ?? 'sin_id'} con riesgo ${riesgo}. Flags: ${original.flags_umbral.join('; ') || 'sin umbrales críticos'}. Score: ${score}. Fuente: ${fuente}.`;

return [{
  json: {
    ...original,
    prediccion: pred,
    riesgo,
    score,
    prioridad,
    fuente_decision: fuente,
    microservice_fallo: failed,
    resumen_clinico: resumen,
    alerta: {
      paciente_id: original.paciente_id,
      tipo: 'riesgo_cardiovascular',
      prioridad,
      riesgo,
      score,
      mensaje: resumen,
      flags: original.flags_umbral,
      origen: 'n8n'
    }
  }
}];
